from fastapi import FastAPI, HTTPException

app = FastAPI()

class User(BaseModel):
    name: str
    email: str

@app.post("/users/")
def create_user(user: User):
    # Validate user input
    try:
        # Validate user input
        if not user.name or not user.email:
            raise ValidationError("Name and email are required")
